import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Electronics = () => {
  const [posts, setPosts] = useState([]);
  const [selectedPost, setSelectedPost] = useState(null);
  const [loading, setLoading] = useState(true);

  const BASE_URL = 'http://localhost:5001';

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const res = await axios.get(`${BASE_URL}/api/blog/Electronics`);
        setPosts(res.data);
        if (res.data.length > 0) {
          setSelectedPost(res.data[0]);
        }
      } catch (err) {
        console.error("Error fetching electronics posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  const getImageUrl = (imagePath) => {
    if (!imagePath) return "https://via.placeholder.com/1200x600?text=Hudson+Electronics+Update";
    if (imagePath.startsWith('http')) return imagePath;
    const cleanPath = imagePath.startsWith('/') ? imagePath : `/${imagePath}`;
    return `${BASE_URL}${cleanPath}`;
  };

  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-gray-50">
      <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
    </div>
  );

  return (
    <div className="bg-[#fcfcfd] min-h-screen antialiased text-slate-900">

      {/* 1. MINIMAL HEADER WITH BREADCRUMB */}
      <header className="pt-24 pb-12 px-6 md:px-16 border-b border-gray-100 bg-white">
        <div className="max-w-screen-2xl mx-auto">
          <div className="flex items-center gap-2 text-sm text-gray-500 mb-4 font-medium">
            <span>Industries</span>
            <span>/</span>
            <span className="text-orange-600 font-semibold">Electronics</span>
          </div>
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter text-gray-950 leading-[0.9]">
            Sector <span className="text-orange-600">Insights</span>
          </h1>
          <p className="mt-6 text-xl text-gray-600 max-w-3xl leading-relaxed font-medium">
            Exploring the forefront of electronic innovation, from precise engineering to global market trends.
          </p>
        </div>
      </header>

      {/* 2. MAIN CONTENT AREA */}
      <main className="max-w-screen-2xl mx-auto px-6 md:px-16 py-16">
        <div className="flex flex-col xl:flex-row gap-16">

          {/* A. LEFT SIDE: IMMERSIVE BLOG ARTICLE */}
          <div className="xl:w-2/3">
            {selectedPost ? (
              <article className="animate-fadeIn">

                {/* Meta Info */}
                <div className="flex items-center gap-6 mb-10 pb-8 border-b border-gray-100">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-full bg-gray-900 flex items-center justify-center text-white font-bold text-xl shadow-lg">H</div>
                    <div>
                      <p className="font-bold text-gray-900">Hudson Editorial</p>
                      <p className="text-sm text-gray-500">Industry Analyst</p>
                    </div>
                  </div>
                  <div className="h-10 w-px bg-gray-100"></div>
                  <div className="text-sm text-gray-500 font-medium">
                    Published: {new Date(selectedPost.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}
                  </div>
                </div>

                {/* Big Featured Image */}
                <div className="rounded-[3rem] overflow-hidden bg-gray-100 mb-12 shadow-[0_40px_100px_-20px_rgba(0,0,0,0.15)]">
                  <img 
                    src={getImageUrl(selectedPost.image)} 
                    alt={selectedPost.title}
                    className="w-full h-[550px] object-cover"
                    onError={(e) => { e.target.src = "https://via.placeholder.com/1200x600?text=Image+Not+Available"; }}
                  />
                </div>

                {/* Title */}
                <h2 className="text-5xl md:text-6xl font-black text-gray-950 mb-10 leading-[1.1] tracking-tighter">
                  {selectedPost.title}
                </h2>

                {/* Content - Typography focused for reading */}
                <div className="prose prose-xl prose-slate max-w-none text-gray-700 leading-relaxed space-y-8 font-serif">
                  {selectedPost.description.split('\n').map((para, i) => (
                    <p key={i} className="text-2xl">{para}</p>
                  ))}
                </div>

              </article>
            ) : (
              <div className="text-center py-32 bg-white rounded-3xl border border-gray-100 shadow-sm">
                <div className="text-8xl mb-6">📂</div>
                <h3 className="text-2xl font-bold text-gray-400">No Electronics Posts Available</h3>
              </div>
            )}
          </div>

          {/* B. RIGHT SIDE: MODERN STICKY SIDEBAR LIST */}
          <div className="xl:w-1/3">
            <div className="sticky top-12 space-y-6">

              <div className="flex items-center justify-between mb-8">
                <h3 className="text-sm font-black uppercase tracking-[0.25em] text-gray-500">
                  Sector Reports
                </h3>
                <span className="text-xs font-bold text-orange-600 bg-orange-100 px-3 py-1 rounded-full">
                  {posts.length} Total
                </span>
              </div>

              {/* Scrollable List Container */}
              <div className="space-y-5 max-h-[70vh] overflow-y-auto pr-3 custom-scrollbar">
                {posts.map((post) => {
                  const isActive = selectedPost?._id === post._id;
                  return (
                    <div 
                      key={post._id}
                      onClick={() => {
                        setSelectedPost(post);
                        window.scrollTo({ top: 0, behavior: 'smooth' });
                      }}
                      className={`group p-7 rounded-3xl cursor-pointer transition-all duration-500 bg-white border ${
                        isActive 
                        ? 'border-orange-400 shadow-[0_20px_50px_-10px_rgba(234,88,12,0.15)] translate-x-2' 
                        : 'border-gray-100 hover:border-gray-200 hover:shadow-lg hover:-translate-y-1'
                      }`}
                    >
                      <div className="flex flex-col gap-3">
                        <div className="flex items-center gap-3">
                          <span className={`w-2 h-2 rounded-full ${isActive ? 'bg-orange-500 animate-pulse' : 'bg-gray-300'}`}></span>
                          <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                            {new Date(post.createdAt).toLocaleDateString('en-GB', { month: 'short', year: 'numeric' })}
                          </p>
                        </div>

                        <h4 className={`text-xl font-extrabold leading-snug tracking-tight ${
                          isActive ? 'text-orange-600' : 'text-gray-950 group-hover:text-orange-600'
                        }`}>
                          {post.title}
                        </h4>

                        <p className={`text-sm line-clamp-2 ${isActive ? 'text-orange-900/80' : 'text-gray-500'}`}>
                          {post.description}
                        </p>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Sidebar CTA Card */}
              <div className="mt-10 p-10 bg-gray-950 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
                <div className="relative z-10">
                  <h4 className="text-2xl font-bold mb-3 tracking-tight">Need expert <br/>analysis?</h4>
                  <p className="text-gray-400 text-sm mb-6 max-w-xs">Connect with Hudson's electronics specialists for tailored insights.</p>
                  <button className="px-6 py-3 bg-orange-600 rounded-xl font-bold text-sm hover:bg-white hover:text-gray-950 transition-all transform hover:scale-105">
                    Contact Specialist
                  </button>
                </div>
                <div className="absolute -bottom-10 -right-10 text-9xl font-black text-gray-800 opacity-50 select-none">H</div>
              </div>

            </div>
          </div>

        </div>
      </main>

    </div>
  );
};

export default Electronics;
